  function pcheck1() {
    var HD;
    var P;
    var I;
    if (game.global.challengeActive != "Daily") {
      HD = getPageSetting2("PraidingHD");
      P = getPageSetting2("PraidingP") > 0 ? getPageSetting2("PraidingP") : 0;
      I = getPageSetting2("PraidingI") > 0 ? getPageSetting2("PraidingI") : 0;
    }
    if (game.global.challengeActive == "Daily") {
      HD = getPageSetting2("dPraidingHD");
      P = getPageSetting2("dPraidingP") > 0 ? getPageSetting2("dPraidingP") : 0;
      I = getPageSetting2("dPraidingI") > 0 ? getPageSetting2("dPraidingI") : 0;
    }
    var go = false;
    if (HD <= 0) {
      go = true;
    } else if (HD > 0) {
      go = HD >= calcHDratio(game.global.world + plusMapToRun1());
    }
    if (P > 0 && getEmpowerment() == "Poison") {
      go = P >= plusMapToRun1();
    }
    if (I > 0 && getEmpowerment() == "Ice") {
      go = I >= plusMapToRun1();
    }
    return go;
  }
